```

---

## 4. 🔧 **UTILITY FUNCTIONS** (`src/utility/attendance.ts`)

```typescript
// src/utility/attendance.ts
import { supabaseClient } from "./supabaseClient";
import { IAttendanceSession, ISantriAttendance, IRekapSantri, IAbsensiFilters, SessionType, AttendanceStatus } from "../types";
import dayjs from "dayjs";

// ===== QR TOKEN GENERATOR =====
export const generateQRToken = (): string => {
  const array = new Uint8Array(32);
  crypto.getRandomValues(array);
  return Array.from(array, b => b.toString(16).padStart(2, '0')).join('');
};

// ===== SESSION CRUD =====
export const createAttendanceSession = async (data: {
  session_date: string;
  session_type: SessionType;
  kelas?: string | null;
  jurusan?: string | null;
  starts_at: string;
  ends_at: string;
  qr_expires_hours?: number;
  created_by: string;
}): Promise<IAttendanceSession> => {
  const qr_code_token = generateQRToken();
  const expires_at = data.qr_expires_hours 
    ? dayjs().add(data.qr_expires_hours, 'hour').toISOString()
    : dayjs(data.session_date).add(1, 'day').toISOString(); // default: berlaku 1 hari

  const { data: session, error } = await supabaseClient
    .from('attendance_sessions')
    .insert({
      ...data,
      qr_code_token,
      qr_expires_at: expires_at,
    })
    .select()
    .single();

  if (error) throw error;
  return session;
};

export const getAttendanceSessions = async (filters: IAbsensiFilters) => {
  let query = supabaseClient
    .from('attendance_sessions')
    .select('*, creator:profiles(full_name)')
    .order('session_date', { ascending: false })
    .order('starts_at', { ascending: true });

  if (filters.tanggal_mulai) query = query.gte('session_date', filters.tanggal_mulai);
  if (filters.tanggal_selesai) query = query.lte('session_date', filters.tanggal_selesai);
  if (filters.session_type && filters.session_type !== 'ALL') query = query.eq('session_type', filters.session_type);
  if (filters.kelas && filters.kelas !== 'ALL') query = query.eq('kelas', filters.kelas);
  if (filters.jurusan && filters.jurusan !== 'ALL') query = query.eq('jurusan', filters.jurusan);

  const { data, error } = await query;
  if (error) throw error;
  return data as IAttendanceSession[];
};

export const getSessionDetail = async (sessionId: string) => {
  const [{ data: session }, { data: records }] = await Promise.all([
    supabaseClient.from('attendance_sessions').select('*, creator:profiles(full_name)').eq('id', sessionId).single(),
    supabaseClient
      .from('santri_attendance')
      .select(`
        *,
        santri:santri(nis, nama, kelas, jurusan, foto_url),
        recorder:profiles(full_name)
      `)
      .eq('session_id', sessionId)
      .order('created_at', { ascending: false })
  ]);

  if (session.error) throw session.error;
  return { session: session.data as IAttendanceSession, records: records as ISantriAttendance[] };
};

// ===== ATTENDANCE RECORDING (QR Scan / Manual) =====
export const recordAttendance = async (params: {
  session_id: string;
  santri_nis: string;
  status: AttendanceStatus;
  recorded_by?: string;
  note?: string;
  check_in_at?: string; // ISO string, default now()
}): Promise<ISantriAttendance> => {
  const check_in_at = params.check_in_at || new Date().toISOString();

  // Upsert: insert atau update jika sudah ada (unique constraint session_id + santri_nis)
  const { data, error } = await supabaseClient
    .from('santri_attendance')
    .upsert({
      session_id: params.session_id,
      santri_nis: params.santri_nis,
      status: params.status,
      check_in_at,
      recorded_by: params.recorded_by,
      note: params.note,
      updated_at: new Date().toISOString(),
    }, {
      onConflict: 'session_id,santri_nis',
      ignoreDuplicates: false
    })
    .select(`
      *,
      santri:santri(nis, nama, kelas, jurusan, foto_url),
      recorder:profiles(full_name)
    `)
    .single();

  if (error) throw error;
  return data as ISantriAttendance;
};

export const bulkRecordAttendance = async (records: Array<{
  session_id: string;
  santri_nis: string;
  status: AttendanceStatus;
  recorded_by?: string;
  note?: string;
}>) => {
  const now = new Date().toISOString();
  const payload = records.map(r => ({
    ...r,
    check_in_at: r.check_in_at || now,
    updated_at: now,
  }));

  const { data, error } = await supabaseClient
    .from('santri_attendance')
    .upsert(payload, { onConflict: 'session_id,santri_nis' })
    .select();

  if (error) throw error;
  return data;
};

// ===== REKAP QUERIES =====
export const getRekapSantri = async (filters: IAbsensiFilters): Promise<IRekapSantri[]> => {
  // Menggunakan RPC untuk performa optimal (aggregasi di DB)
  const { data, error } = await supabaseClient.rpc('get_rekap_absensi_santri', {
    p_tanggal_mulai: filters.tanggal_mulai || null,
    p_tanggal_selesai: filters.tanggal_selesai || null,
    p_session_type: filters.session_type !== 'ALL' ? filters.session_type : null,
    p_kelas: filters.kelas !== 'ALL' ? filters.kelas : null,
    p_jurusan: filters.jurusan !== 'ALL' ? filters.jurusan : null,
  });

  if (error) throw error;
  return data as IRekapSantri[];
};

export const getRekapKelas = async (filters: IAbsensiFilters) => {
  const { data, error } = await supabaseClient.rpc('get_rekap_absensi_kelas', {
    p_tanggal_mulai: filters.tanggal_mulai || null,
    p_tanggal_selesai: filters.tanggal_selesai || null,
    p_session_type: filters.session_type !== 'ALL' ? filters.session_type : null,
    p_jurusan: filters.jurusan !== 'ALL' ? filters.jurusan : null,
  });

  if (error) throw error;
  return data;
};

// ===== EXPORT HELPERS =====
export const formatTanggalIndonesia = (dateStr: string): string => {
  return dayjs(dateStr).locale('id').format('dddd, DD MMMM YYYY');
};

export const getSessionTypeLabel = (type: SessionType): string => SESSION_TYPE_LABELS[type];
export const getStatusColor = (status: AttendanceStatus): string => ATTENDANCE_STATUS_COLORS[status];
```

---

## 5. 🗃️ **DATABASE RPC FUNCTIONS** (Untuk Rekap Performa Tinggi)

```sql
-- Function: get_rekap_absensi_santri
CREATE OR REPLACE FUNCTION public.get_rekap_absensi_santri(
  p_tanggal_mulai DATE DEFAULT NULL,
  p_tanggal_selesai DATE DEFAULT NULL,
  p_session_type TEXT DEFAULT NULL,
  p_kelas TEXT DEFAULT NULL,
  p_jurusan TEXT DEFAULT NULL
)
RETURNS TABLE (
  santri_nis TEXT,
  nama TEXT,
  kelas TEXT,
  jurusan TEXT,
  total_sesi BIGINT,
  hadir BIGINT,
  izin BIGINT,
  sakit BIGINT,
  alpa BIGINT,
  terlambat BIGINT,
  cuti BIGINT,
  dispensasi BIGINT,
  representasi BIGINT,
  persentase_kehadiran NUMERIC
)
LANGUAGE sql
STABLE
AS $$
  SELECT 
    s.nis AS santri_nis,
    s.nama,
    s.kelas,
    s.jurusan,
    COUNT(sa.id) AS total_sesi,
    COUNT(*) FILTER (WHERE sa.status = 'HADIR') AS hadir,
    COUNT(*) FILTER (WHERE sa.status = 'IZIN') AS izin,
    COUNT(*) FILTER (WHERE sa.status = 'SAKIT') AS sakit,
    COUNT(*) FILTER (WHERE sa.status = 'ALPA') AS alpa,
    COUNT(*) FILTER (WHERE sa.status = 'TERLAMBAT') AS terlambat,
    COUNT(*) FILTER (WHERE sa.status = 'CUTI') AS cuti,
    COUNT(*) FILTER (WHERE sa.status = 'DISPENSASI') AS dispensasi,
    COUNT(*) FILTER (WHERE sa.status = 'REPRESENTASI') AS representasi,
    CASE 
      WHEN COUNT(sa.id) > 0 
      THEN ROUND(
        (COUNT(*) FILTER (WHERE sa.status IN ('HADIR', 'TERLAMBAT', 'REPRESENTASI'))::numeric 
         / COUNT(sa.id)) * 100, 2)
      ELSE 0 
    END AS persentase_kehadiran
  FROM santri s
  LEFT JOIN santri_attendance sa ON sa.santri_nis = s.nis
  LEFT JOIN attendance_sessions sess ON sess.id = sa.session_id
  WHERE s.status_santri = 'AKTIF'
    AND (p_tanggal_mulai IS NULL OR sess.session_date >= p_tanggal_mulai)
    AND (p_tanggal_selesai IS NULL OR sess.session_date <= p_tanggal_selesai)
    AND (p_session_type IS NULL OR sess.session_type = p_session_type)
    AND (p_kelas IS NULL OR s.kelas = p_kelas)
    AND (p_jurusan IS NULL OR s.jurusan = p_jurusan)
  GROUP BY s.nis, s.nama, s.kelas, s.jurusan
  ORDER BY s.kelas, s.nama;
$$;

-- Function: get_rekap_absensi_kelas
CREATE OR REPLACE FUNCTION public.get_rekap_absensi_kelas(
  p_tanggal_mulai DATE DEFAULT NULL,
  p_tanggal_selesai DATE DEFAULT NULL,
  p_session_type TEXT DEFAULT NULL,
  p_jurusan TEXT DEFAULT NULL
)
RETURNS TABLE (
  kelas TEXT,
  jurusan TEXT,
  total_santri BIGINT,
  total_sesi BIGINT,
  rata_rata_kehadiran NUMERIC,
  detail JSONB
)
LANGUAGE sql
STABLE
AS $$
  SELECT 
    s.kelas,
    s.jurusan,
    COUNT(DISTINCT s.nis) AS total_santri,
    COUNT(sa.id) AS total_sesi,
    ROUND(AVG(
      CASE 
        WHEN cnt > 0 
        THEN (present::numeric / cnt) * 100 
        ELSE 0 
      END
    ), 2) AS rata_rata_kehadiran,
    JSONB_AGG(
      JSONB_BUILD_OBJECT(
        'santri_nis', s.nis,
        'nama', s.nama,
        'hadir', hadir,
        'izin', izin,
        'sakit', sakit,
        'alpa', alpa,
        'terlambat', terlambat,
        'persentase', CASE WHEN cnt > 0 THEN ROUND((present::numeric / cnt) * 100, 2) ELSE 0 END
      ) ORDER BY s.nama
    ) AS detail
  FROM santri s
  LEFT JOIN (
    SELECT 
      sa.santri_nis,
      COUNT(*) AS cnt,
      COUNT(*) FILTER (WHERE sa.status IN ('HADIR', 'TERLAMBAT', 'REPRESENTASI')) AS present,
      COUNT(*) FILTER (WHERE sa.status = 'HADIR') AS hadir,
      COUNT(*) FILTER (WHERE sa.status = 'IZIN') AS izin,
      COUNT(*) FILTER (WHERE sa.status = 'SAKIT') AS sakit,
      COUNT(*) FILTER (WHERE sa.status = 'ALPA') AS alpa,
      COUNT(*) FILTER (WHERE sa.status = 'TERLAMBAT') AS terlambat
    FROM santri_attendance sa
    JOIN attendance_sessions sess ON sess.id = sa.session_id
    WHERE (p_tanggal_mulai IS NULL OR sess.session_date >= p_tanggal_mulai)
      AND (p_tanggal_selesai IS NULL OR sess.session_date <= p_tanggal_selesai)
      AND (p_session_type IS NULL OR sess.session_type = p_session_type)
    GROUP BY sa.santri_nis
  ) agg ON agg.santri_nis = s.nis
  WHERE s.status_santri = 'AKTIF'
    AND (p_jurusan IS NULL OR s.jurusan = p_jurusan)
  GROUP BY s.kelas, s.jurusan
  ORDER BY s.kelas, s.jurusan;
$$;
```

---

## 6. 🖥️ **PAGES STRUCTURE** (`src/pages/absensi/`)

```
src/pages/absensi/
├── list.tsx          # /absensi - Dashboard sesi absensi (filter, card summary)
├── create.tsx        # /absensi/create - Buat sesi baru + generate QR
├── edit.tsx          # /absensi/edit/:id - Edit sesi (extend QR, ubah jam)
├── detail.tsx        # /absensi/detail/:id - Detail sesi: tabel santri + inline edit status
├── rekap.tsx         # /absensi/rekap - Laporan: filter, tabel rekap, export Excel/PDF
└── scan.tsx          # /absensi/scan/:token - **PUBLIC** page untuk santri scan QR
```

### 6.1 **AbsensiList** (`/absensi`)
- **Header**: Filter tanggal (range picker), session_type (dropdown), kelas, jurusan
- **Summary Cards**: Total Sesi, Total Santri, Hadir, Alpa, Persentase Kehadiran
- **Table**: Kolom Tanggal, Jenis, Kelas/Jurusan, Jam, Status QR (Aktif/Expired), Aksi (Edit, Detail, Hapus)
- **Actions**: "Buat Sesi Baru" button → navigate ke Create

### 6.2 **AbsensiCreate** (`/absensi/create`)
- **Form**: Tanggal, Jenis Sesi (Shalat/Akademik - grouped), Kelas (opsional), Jurusan (opsional), Jam Mulai/Selesai, Durasi QR berlaku (jam)
- **Preview QR**: Generate QR code real-time (pakai `qrcode.react`)
- **Submit**: Simpan → redirect ke Detail dengan QR siap print/share

### 6.3 **AbsensiDetail** (`/absensi/detail/:id`)
- **Header Info**: Tanggal, Jenis, Kelas, Jam, QR Code (besar, printable), Status QR
- **Tab**: [Santri Belum Absen] | [Sudah Absen] | [Semua]
- **Table Santri**: Foto, NIS, Nama, Kelas, Status (badge + dropdown inline edit), Waktu Check-in, Dicatat Oleh
- **Bulk Actions**: "Set Semua Hadir", "Set Semua Alpa" (untuk ustadz cepat input)
- **Export**: Download Excel/PDF rekap sesi ini

### 6.4 **AbsensiRekap** (`/absensi/rekap`)
- **Filter Panel**: Rentang Tanggal, Jenis Sesi, Kelas, Jurusan, Status
- **View Mode Toggle**: [Per Santri] | [Per Kelas] | [Per Bulan]
- **Table Per Santri**: NIS, Nama, Kelas, Total Sesi, Hadir, Izin, Sakit, Alpa, Terlambat, % Kehadiran
- **Table Per Kelas**: Kelas, Jurusan, Total Santri, Rata-rata Kehadiran, Detail (expandable)
- **Export Buttons**: 
  - 📊 **Excel** (multi-sheet: Santri, Kelas, Ringkasan)
  - 📄 **PDF** (formatted laporan resmi dengan header instansi)

### 6.5 **AbsensiScan** (`/absensi/scan/:token`) — **PUBLIC PAGE**
- **No Auth Required** — diakses via QR code scan dari HP santri
- **Validasi Token**: Cek `attendance_sessions` by `qr_code_token`, validasi `qr_expires_at` > now()
- **UI**: 
  - Jika valid → tampilkan info sesi + form pilih status (HADIR/TERLAMBAT/IZIN/SAKIT)
  - Santri klik status → call `recordAttendance` via Supabase client (anon key)
  - Success → tampilkan konfirmasi + nama santri + jam check-in
  - Error → token expired / sudah absen / sesi tidak aktif
- **Fallback**: Jika QR rusak, ada input manual NIS

