## 9. 📊 **EXPORT IMPLEMENTASI**

### 9.1 **Excel Export** (`src/utility/exportAttendance.ts`)
```typescript
import * as XLSX from 'xlsx';
import { saveAs } from 'file-saver';
import { IRekapSantri, IRekapKelas, IAttendanceSession, ISantriAttendance } from "../types";
import { formatTanggalIndonesia, getSessionTypeLabel, getStatusColor } from "./attendance";

export const exportAbsensiToExcel = (params: {
  sessions?: IAttendanceSession[];
  rekapSantri?: IRekapSantri[];
  rekapKelas?: IRekapKelas[];
  detailRecords?: ISantriAttendance[];
  filename?: string;
}) => {
  const wb = XLSX.utils.book_new();

  // Sheet 1: Ringkasan Sesi
  if (params.sessions?.length) {
    const ws = XLSX.utils.json_to_sheet(params.sessions.map(s => ({
      Tanggal: formatTanggalIndonesia(s.session_date),
      Jenis: getSessionTypeLabel(s.session_type),
      Kelas: s.kelas || 'Semua',
      Jurusan: s.jurusan || 'Semua',
      'Jam Mulai': s.starts_at.slice(0,5),
      'Jam Selesai': s.ends_at.slice(0,5),
      'Status QR': s.is_active && (!s.qr_expires_at || new Date(s.qr_expires_at) > new Date()) ? 'Aktif' : 'Expired',
      Dibuat: new Date(s.created_at).toLocaleString('id-ID'),
    })));
    XLSX.utils.book_append_sheet(wb, ws, 'Ringkasan Sesi');
  }

  // Sheet 2: Rekap Per Santri
  if (params.rekapSantri?.length) {
    const ws = XLSX.utils.json_to_sheet(params.rekapSantri.map(r => ({
      NIS: r.santri_nis,
      Nama: r.nama,
      Kelas: r.kelas,
      Jurusan: r.jurusan,
      'Total Sesi': r.total_sesi,
      Hadir: r.hadir,
      Izin: r.izin,
      Sakit: r.sakit,
      Alpa: r.alpa,
      Terlambat: r.terlambat,
      Cuti: r.cuti,
      Dispensasi: r.dispensasi,
      Representasi: r.representasi,
      '% Kehadiran': r.persentase_kehadiran,
    })));
    XLSX.utils.book_append_sheet(wb, ws, 'Rekap Santri');
  }

  // Sheet 3: Rekap Per Kelas
  if (params.rekapKelas?.length) {
    const ws = XLSX.utils.json_to_sheet(params.rekapKelas.map(r => ({
      Kelas: r.kelas,
      Jurusan: r.jurusan,
      'Total Santri': r.total_santri,
      'Total Sesi': r.total_sesi,
      'Rata-rata Kehadiran (%)': r.rata_rata_kehadiran,
    })));
    XLSX.utils.book_append_sheet(wb, ws, 'Rekap Kelas');
  }

  // Sheet 4: Detail Records (optional)
  if (params.detailRecords?.length) {
    const ws = XLSX.utils.json_to_sheet(params.detailRecords.map(r => ({
      NIS: r.santri_nis,
      Nama: r.santri?.nama,
      Kelas: r.santri?.kelas,
      Status: r.status,
      'Waktu Check-in': r.check_in_at ? new Date(r.check_in_at).toLocaleString('id-ID') : '-',
      'Dicatat Oleh': r.recorder?.full_name,
      Catatan: r.note || '-',
    })));
    XLSX.utils.book_append_sheet(wb, ws, 'Detail');
  }

  const filename = params.filename || `absensi_${dayjs().format('YYYYMMDD_HHmm')}.xlsx`;
  const wbout = XLSX.write(wb, { bookType: 'xlsx', type: 'array' });
  saveAs(new Blob([wbout], { type: 'application/octet-stream' }), filename);
};
```

